class Solution(object):
    def numberOfSubarrays(self, nums, k):
        from collections import defaultdict
        freq = defaultdict(int)
        freq[0] = 1
        result = 0
        prefix_odd_count = 0
        for num in nums:
            if num % 2 == 1:
                prefix_odd_count += 1
            result += freq[prefix_odd_count - k]
            freq[prefix_odd_count] += 1
        return result
